import { useMemo } from 'react';
import { useSectionProgress } from '@/hooks/use-section-progress';
import { motion } from 'motion/react';
import { SegmentedProgressBar } from './segmented-progress-bar';
import type { MouseEvent } from 'react';

// Reusing types from AnimatedToc if possible, or redefining.
export interface TocItem {
    id: string;
    label: string;
    level: number;
}

export interface SegmentedTocProps {
    items: TocItem[];
    activeId?: string;
    onSectionClick?: (id: string) => void;
}

export function SegmentedToc({ items, activeId, onSectionClick }: SegmentedTocProps) {
    const sectionIds = useMemo(() => items.map(item => item.id), [items]);
    const progressMap = useSectionProgress(sectionIds);

    // If activeId is provided, we use it directly.
    // Otherwise we fall back to the scroll-based heuristic.
    const activeIndex = useMemo(() => {
        if (activeId) {
            return items.findIndex(item => item.id === activeId);
        }

        // ... existing heuristic ...
        const inProgressIndex = items.findIndex(item => {
            const p = progressMap[item.id] || 0;
            return p > 0 && p < 1;
        });

        if (inProgressIndex !== -1) return inProgressIndex;

        for (let i = items.length - 1; i >= 0; i--) {
            if ((progressMap[items[i].id] || 0) >= 0.99) {
                return i;
            }
        }

        return 0;
    }, [items, progressMap, activeId]);

    // Construct a simulated progress map if we are in manual mode
    const effectiveProgressMap = useMemo(() => {
        if (activeId) {
            const map: Record<string, number> = {};
            const index = items.findIndex(item => item.id === activeId);
            items.forEach((item, i) => {
                if (i < index) map[item.id] = 1;
                else if (i === index) map[item.id] = 0.5; // Active
                else map[item.id] = 0;
            });
            return map;
        }
        return progressMap;
    }, [activeId, items, progressMap]);

    const handleItemClick = (id: string) => {
        if (onSectionClick) {
            onSectionClick(id);
        } else {
            document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
        }
    };

    return (
        <nav
            className="w-full max-w-[24rem] rounded-xl p-5 shadow-2xl transition-colors duration-500"
            style={{ backgroundColor: 'var(--card-bg)', border: '1px solid var(--card-border)' }}
            aria-label="Table of contents"
        >
            <h2
                className="mb-3 text-[10px] font-mono font-normal tracking-normal uppercase transition-colors duration-500"
                style={{ color: 'var(--muted)' }}
            > {/* Reduced size, margin, tracking */}
                Table of Contents
            </h2>

            {/* Progress Bar Container */}
            <SegmentedProgressBar
                items={items}
                activeIndex={activeIndex}
                progressMap={effectiveProgressMap}
                onItemClick={handleItemClick}
            />

            {/* List Items */}
            <ul className="space-y-0.5 mt-4"> {/* Reduced spacing and margin */}
                {items.map((item, index) => (
                    <TocLink
                        key={item.id}
                        item={item}
                        index={index}
                        isActive={index === activeIndex}
                        onClick={() => handleItemClick(item.id)}
                    />
                ))}
            </ul>
        </nav>
    );
}



function TocLink({ item, index, isActive, onClick }: { item: TocItem, index: number, isActive: boolean, onClick?: () => void }) {
    // Numbering: 01, 02, etc.
    const number = String(index + 1).padStart(2, '0');

    return (
        <motion.li
            className="group" // Add group for hover targeting
            animate={{
                opacity: isActive ? 1 : 0.7,
            }}
            transition={{
                type: "spring",
                stiffness: 280,
                damping: 24
            }}
        >
            <motion.a
                href={\`#\${item.id}\`}
                onClick={(e: MouseEvent<HTMLAnchorElement>) => {
                    e.preventDefault();
                    if (onClick) onClick();
                }}
                className="flex items-baseline gap-3 text-xs font-mono uppercase tracking-normal leading-tight block py-0.5" // Reduced gap, text size, tracking, padding
                initial={false}
                animate={{
                    color: isActive ? 'var(--dot-fill)' : 'var(--muted)',
                    fontWeight: isActive ? 400 : 300 // Lighter weights
                }}
                transition={{
                    duration: 0.3,
                    ease: "easeInOut"
                }}
                whileHover={{ color: isActive ? 'var(--dot-fill)' : 'var(--label-fg)' }}
            >
                <span
                    className="text-[10px] transition-colors duration-500"
                    style={{ color: isActive ? 'var(--label-fg)' : 'var(--muted)' }}
                > {/* Reduced size */}
                    {number}
                </span>
                <span>
                    {item.label}
                </span>
            </motion.a>
        </motion.li >
    );
}
